import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';
import { PlusCircle, Store, ArrowLeft, Loader2, Navigation, MapPin, Trash2, PackageSearch } from 'lucide-react';
import { useAuth } from '../context/AuthContext';
import { useNavigate } from 'react-router-dom'; // Importante para navegar

// Fix Iconos Leaflet
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon-2x.png',
  iconUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-icon.png',
  shadowUrl: 'https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.7.1/images/marker-shadow.png',
});

const DashboardVendedor = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [locales, setLocales] = useState([]);
  const [localActivo, setLocalActivo] = useState(null);
  const [mostrarFormLocal, setMostrarFormLocal] = useState(false);
  const [buscandoDireccion, setBuscandoDireccion] = useState(false);

  const [nuevoLocal, setNuevoLocal] = useState({
    nombre: '', direccion: '', lng: -65.2176, lat: -26.8161
  });

  const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

  useEffect(() => { if (user) fetchLocales(); }, [user]);

  const fetchLocales = async () => {
    try {
      const res = await axios.get(`${API_URL}/api/locales/vendedor/${user.id || user._id}`);
      setLocales(res.data);
    } catch (err) { console.error(err); }
  };

  const fetchAddress = async (lat, lng) => {
    setBuscandoDireccion(true);
    try {
      const res = await axios.get(`${API_URL}/api/locales/reverse-geocode`, { params: { lat, lon: lng } });
      if (res.data && res.data.address) {
        const a = res.data.address;
        const dir = `${a.road || ''} ${a.house_number || ''}, ${a.city || a.town || ''}`.trim();
        setNuevoLocal(prev => ({ ...prev, direccion: dir, lat, lng }));
      }
    } catch (error) { setNuevoLocal(prev => ({ ...prev, lat, lng })); }
    finally { setBuscandoDireccion(false); }
  };

  const handleCrearLocal = async (e) => {
    e.preventDefault();
    try {
      await axios.post(`${API_URL}/api/locales`, { ...nuevoLocal, vendedorId: user.id || user._id });
      fetchLocales();
      setMostrarFormLocal(false);
    } catch (err) { alert("Error al guardar local"); }
  };

  if (!localActivo) {
    return (
      <div style={containerStyle}>
        <div style={headerStyle}>
          <h2>Mis Locales</h2>
          <button onClick={() => setMostrarFormLocal(!mostrarFormLocal)} style={btnPrimary}>
            {mostrarFormLocal ? 'Cancelar' : <><PlusCircle size={18}/> Nuevo Local</>}
          </button>
        </div>

        {mostrarFormLocal ? (
          <div style={formCard}>
            <div style={formLayout}>
              <form onSubmit={handleCrearLocal} style={inputsContainer}>
                <label style={labelL}>Nombre del Local</label>
                <input style={inputS} value={nuevoLocal.nombre} onChange={e => setNuevoLocal({...nuevoLocal, nombre: e.target.value})} required />
                <label style={labelL}>Dirección (Toca el mapa)</label>
                <div style={{position:'relative'}}>
                  <input style={inputS} value={nuevoLocal.direccion} onChange={e => setNuevoLocal({...nuevoLocal, direccion: e.target.value})} required />
                  {buscandoDireccion && <Loader2 size={18} style={spinner} />}
                </div>
                <button type="submit" style={btnSubmit}>Guardar Local</button>
              </form>
              <MapContainer center={[nuevoLocal.lat, nuevoLocal.lng]} zoom={14} style={mapStyle}>
                <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
                <LocationMarker fetchAddress={fetchAddress} position={[nuevoLocal.lat, nuevoLocal.lng]} />
              </MapContainer>
            </div>
          </div>
        ) : (
          <div style={gridLocales}>
            {locales.map(l => (
              <div key={l._id} style={cardLocal} onClick={() => setLocalActivo(l)}>
                <Store size={40} color="#e67e22" />
                <h3>{l.nombre}</h3>
                <p>{l.direccion}</p>
              </div>
            ))}
          </div>
        )}
      </div>
    );
  }

  // --- VISTA CUANDO EL VENDEDOR ENTRA A UN LOCAL ---
  return (
    <div style={containerStyle}>
       <button onClick={() => setLocalActivo(null)} style={btnBack}><ArrowLeft size={18}/> Volver</button>
       <div style={panelActivo}>
          <div>
            <h1 style={{margin:0}}>{localActivo.nombre}</h1>
            <p style={{color:'#64748b'}}><MapPin size={14}/> {localActivo.direccion}</p>
          </div>
          
          {/* ESTE ES EL BOTÓN QUE BUSCABAS */}
          <button 
            onClick={() => navigate(`/gestion-ofertas/${localActivo._id}`)} 
            style={btnGestionar}
          >
            <PackageSearch size={22} />
            Gestionar Productos y Ofertas
          </button>
       </div>
    </div>
  );
};

// Componente auxiliar para el click en el mapa
const LocationMarker = ({ fetchAddress, position }) => {
  useMapEvents({ click(e) { fetchAddress(e.latlng.lat, e.latlng.lng); } });
  return <Marker position={position} />;
};

// Estilos adicionales
const containerStyle = { padding: '40px 20px', maxWidth: '1000px', margin: '0 auto', fontFamily: 'sans-serif' };
const headerStyle = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '30px' };
const btnPrimary = { background: '#e67e22', color: 'white', border: 'none', padding: '12px 24px', borderRadius: '12px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', gap: '8px' };
const formCard = { background: 'white', padding: '30px', borderRadius: '20px', boxShadow: '0 10px 30px rgba(0,0,0,0.05)' };
const formLayout = { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '20px' };
const inputsContainer = { display: 'flex', flexDirection: 'column', gap: '15px' };
const inputS = { width: '100%', padding: '12px', borderRadius: '10px', border: '1.5px solid #f1f5f9' };
const labelL = { fontSize: '0.7rem', fontWeight: 'bold', color: '#94a3b8', textTransform: 'uppercase' };
const mapStyle = { height: '350px', borderRadius: '15px' };
const btnSubmit = { background: '#1e293b', color: 'white', padding: '15px', border: 'none', borderRadius: '12px', cursor: 'pointer', fontWeight: 'bold' };
const gridLocales = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px' };
const cardLocal = { background: 'white', padding: '30px', borderRadius: '20px', border: '1px solid #f1f5f9', textAlign: 'center', cursor: 'pointer' };
const btnBack = { background: 'none', border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '20px' };
const panelActivo = { background: 'white', padding: '40px', borderRadius: '24px', border: '1px solid #e2e8f0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' };
const btnGestionar = { background: '#1e293b', color: 'white', border: 'none', padding: '20px 30px', borderRadius: '16px', cursor: 'pointer', fontWeight: 'bold', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '10px', transition: '0.2s' };
const spinner = { position: 'absolute', right: '10px', top: '12px', animation: 'spin 1s linear infinite' };

export default DashboardVendedor;
